def calculate_total(orders, tax_rates, discount_codes):
    """
    Calculate the total cost of customer orders with discounts and taxes.

    :param orders: List of dictionaries, each representing an order with the following keys:
                   - 'items': List of dictionaries, each with 'name', 'price', and 'quantity'
                   - 'discount_code': String representing the discount code
    :param tax_rates: Dictionary with state codes as keys and tax rates as values
    :param discount_codes: Dictionary with discount codes as keys and discount details as values
                           Discount types: 'percentage', 'fixed_amount', 'buy_one_get_one'
    :return: Itemized receipt as a dictionary
    """
    receipt = {}

    for order in orders:
        order_total = 0
        order_items = []

        for item in order['items']:
            item_total = item['price'] * item['quantity']
            order_items.append({
                'name': item['name'],
                'price': item['price'],
                'quantity': item['quantity'],
                'total': item_total
            })
            order_total += item_total

        # Apply discount
        if order['discount_code'] in discount_codes:
            discount_type, discount_value = discount_codes[order['discount_code']]
            if discount_type == 'percentage':
                order_total *= (1 - discount_value / 100)
            elif discount_type == 'fixed_amount':
                order_total -= discount_value
            elif discount_type == 'buy_one_get_one':
                total_items = sum(item['quantity'] for item in order['items'])
                free_items = total_items // 2
                order_total -= (free_items * (order_total / total_items))

        # Apply tax
        state = order.get('state', 'default')
        tax_rate = tax_rates.get(state, 0)
        tax_amount = order_total * tax_rate
        order_total += tax_amount

        # Update receipt
        receipt[order['discount_code']] = {
            'items': order_items,
            'order_total': order_total,
            'tax_amount': tax_amount
        }

    return receipt

